  1→use std::collections::{BTreeMap, HashMap};
  2→use std::fs::File;
  3→use std::io::{BufRead, BufReader};
  4→use std::path::PathBuf;
  5→
  6→use clap::Parser;
  7→
  8→use ccs_viewer::types::Record;
  9→
 10→#[derive(Parser)]
 11→#[command(version, about = "Claude Code session JSONL viewer")]
 12→struct Cli {
 13→    /// File or directory glob patterns to process
 14→    #[arg(required = true)]
 15→    patterns: Vec<String>,
 16→
 17→    /// Show per-file summary lines
 18→    #[arg(short, long)]
 19→    list: bool,
 20→
 21→    /// Show grouped error details
 22→    #[arg(short, long)]
 23→    errors: bool,
 24→
 25→    /// Recursively search directories for matching files
 26→    #[arg(short, long)]
 27→    recursive: bool,
 28→
 29→    /// File glob pattern for recursive mode (repeatable, default: *.jsonl)
 30→    #[arg(long = "glob")]
 31→    globs: Vec<String>,
 32→}
 33→
 34→/// Resolve CLI patterns into a list of file paths.
 35→fn resolve_files(cli: &Cli) -> Vec<PathBuf> {
 36→    let mut files = Vec::new();
 37→
 38→    if cli.recursive {
 39→        let file_globs: Vec<&str> = if cli.globs.is_empty() {
 40→            vec!["*.jsonl"]
 41→        } else {
 42→            cli.globs.iter().map(|s| s.as_str()).collect()
 43→        };
 44→
 45→        // Expand positional patterns as directory globs.
 46→        for pattern in &cli.patterns {
 47→            let dirs: Vec<PathBuf> = match glob::glob(pattern) {
 48→                Ok(paths) => paths
 49→                    .filter_map(|p| p.ok())
 50→                    .filter(|p| p.is_dir())
 51→                    .collect(),
 52→                Err(e) => {
 53→                    eprintln!("Bad pattern {pattern:?}: {e}");
 54→                    std::process::exit(1);
 55→                }
 56→            };
 57→            if dirs.is_empty() {
 58→                eprintln!("No directories match {pattern:?}");
 59→                std::process::exit(1);
 60→            }
 61→            for dir in &dirs {
 62→                for fg in &file_globs {
 63→                    let full = format!("{}/**/{fg}", dir.display());
 64→                    match glob::glob(&full) {
 65→                        Ok(paths) => {
 66→                            for entry in paths.flatten() {
 67→                                if entry.is_file() {
 68→                                    files.push(entry);
 69→                                }
 70→                            }
 71→                        }
 72→                        Err(e) => {
 73→                            eprintln!("Bad glob {full:?}: {e}");
 74→                            std::process::exit(1);
 75→                        }
 76→                    }
 77→                }
 78→            }
 79→        }
 80→    } else {
 81→        let file_globs: Vec<&str> = if cli.globs.is_empty() {
 82→            vec!["*.jsonl"]
 83→        } else {
 84→            cli.globs.iter().map(|s| s.as_str()).collect()
 85→        };
 86→
 87→        for pattern in &cli.patterns {
 88→            // Check if pattern is a literal directory path first.
 89→            let path = PathBuf::from(pattern);
 90→            if path.is_dir() {
 91→                // Directory: expand file globs inside it (non-recursive).
 92→                for fg in &file_globs {
 93→                    let full = format!("{}/{fg}", path.display());
 94→                    match glob::glob(&full) {
 95→                        Ok(paths) => {
 96→                            for entry in paths.flatten() {
 97→                                if entry.is_file() {
 98→                                    files.push(entry);
 99→                                }
100→                            }
101→                        }
102→                        Err(e) => {
103→                            eprintln!("Bad glob {full:?}: {e}");
104→                            std::process::exit(1);
105→                        }
106→                    }
107→                }
108→            } else {
109→                // Treat as file glob pattern.
110→                match glob::glob(pattern) {
111→                    Ok(paths) => {
112→                        let mut matched = Vec::new();
113→                        for entry in paths.flatten() {
114→                            if entry.is_file() {
115→                                matched.push(entry);
116→                            } else if entry.is_dir() {
117→                                // Glob matched a directory: expand file
118→                                // globs inside it (non-recursive).
119→                                for fg in &file_globs {
120→                                    let full = format!("{}/{fg}", entry.display());
121→                                    if let Ok(inner) = glob::glob(&full) {
122→                                        for f in inner.flatten() {
123→                                            if f.is_file() {
124→                                                matched.push(f);
125→                                            }
126→                                        }
127→                                    }
128→                                }
129→                            }
130→                        }
131→                        if matched.is_empty() {
132→                            eprintln!("No files match {pattern:?}");
133→                            std::process::exit(1);
134→                        }
135→                        files.extend(matched);
136→                    }
137→                    Err(e) => {
138→                        eprintln!("Bad pattern {pattern:?}: {e}");
139→                        std::process::exit(1);
140→                    }
141→                }
142→            }
143→        }
144→    }
145→
146→    files.sort();
147→    files.dedup();
148→    files
149→}
150→
151→/// Key for grouping errors: the serde error message + record type.
152→#[derive(Hash, Eq, PartialEq)]
153→struct ErrorKey {
154→    message: String,
155→    record_type: String,
156→}
157→
158→/// Tracks one group of identical errors across files.
159→struct ErrorGroup {
160→    count: usize,
161→    /// One representative file:line for grabbing test data.
162→    example_file: String,
163→    example_line: usize,
164→    /// How many distinct files contain this error.
165→    file_count: usize,
166→    /// Track which files we've seen (by index) to count distinct files.
167→    seen_files: Vec<usize>,
168→}
169→
170→fn main() {
171→    let cli = Cli::parse();
172→    let files = resolve_files(&cli);
173→
174→    if files.is_empty() {
175→        eprintln!("No files to process");
176→        std::process::exit(1);
177→    }
178→
179→    let mut total_records: usize = 0;
180→    let mut total_errors: usize = 0;
181→    let mut error_groups: HashMap<ErrorKey, ErrorGroup> = HashMap::new();
182→
183→    for (file_idx, path) in files.iter().enumerate() {
184→        let file = File::open(path).unwrap_or_else(|e| {
185→            eprintln!("Error opening {}: {e}", path.display());
186→            std::process::exit(1);
187→        });
188→
189→        let reader = BufReader::new(file);
190→        let mut counts: BTreeMap<&str, usize> = BTreeMap::new();
191→        let mut file_errors: usize = 0;
192→        let filename = path
193→            .file_name()
194→            .map(|f| f.to_string_lossy().into_owned())
195→            .unwrap_or_else(|| path.display().to_string());
196→
197→        for (i, line) in reader.lines().enumerate() {
198→            let line = line.unwrap_or_else(|e| {
199→                eprintln!("Error reading line {}: {e}", i + 1);
200→                std::process::exit(1);
201→            });
202→            if line.trim().is_empty() {
203→                continue;
204→            }
205→            match serde_json::from_str::<Record>(&line) {
206→                Ok(record) => {
207→                    *counts.entry(record.label()).or_insert(0) += 1;
208→                }
209→                Err(e) => {
210→                    file_errors += 1;
211→                    let record_type = serde_json::from_str::<serde_json::Value>(&line)
212→                        .ok()
213→                        .and_then(|v| v.get("type")?.as_str().map(String::from))
214→                        .unwrap_or_else(|| "unknown".to_string());
215→
216→                    let key = ErrorKey {
217→                        message: format!("{e}"),
218→                        record_type,
219→                    };
220→                    let group = error_groups.entry(key).or_insert_with(|| ErrorGroup {
221→                        count: 0,
222→                        example_file: filename.clone(),
223→                        example_line: i + 1,
224→                        file_count: 0,
225→                        seen_files: Vec::new(),
226→                    });
227→                    group.count += 1;
228→                    if !group.seen_files.contains(&file_idx) {
229→                        group.seen_files.push(file_idx);
230→                        group.file_count += 1;
231→                    }
232→                }
233→            }
234→        }
235→
236→        let file_total: usize = counts.values().sum();
237→        total_records += file_total;
238→        total_errors += file_errors;
239→
240→        if cli.list {
241→            let mut parts = vec![
242→                format!("errors: {file_errors}"),
243→                format!("records: {file_total}"),
244→            ];
245→            for (label, count) in &counts {
246→                parts.push(format!("{label}: {count}"));
247→            }
248→            println!("{filename}: {}", parts.join(", "));
249→        }
250→    }
251→
252→    let file_count = files.len();
253→    println!(
254→        "{}Summary: {file_count} file(s), {total_records} records, {total_errors} errors",
255→        if cli.list { "\n" } else { "" }
256→    );
257→
258→    if cli.errors && !error_groups.is_empty() {
259→        println!("\nErrors:");
260→        let mut groups: Vec<_> = error_groups.into_iter().collect();
261→        groups.sort_by(|a, b| b.1.count.cmp(&a.1.count));
262→        for (key, group) in &groups {
263→            println!(
264→                "  {}x {} in {} ({}:{} in {} file(s))",
265→                group.count,
266→                key.message,
267→                key.record_type,
268→                group.example_file,
269→                group.example_line,
270→                group.file_count,
271→            );
272→        }
273→    }
274→
275→    if total_errors > 0 {
276→        std::process::exit(1);
277→    }
278→}
