#[cfg(test)]
mod tests {
    use super::*;
    use std::collections::HashSet;
    use std::fs::File;
    use std::io::{BufRead, BufReader};

    const TEST_FILES: &[&str] = &[
        "data/31ba272b-f7c2-436b-a017-269e27a64d07.jsonl",
        "data/997afb98-c6aa-4f4a-92ac-a841e040414b.jsonl",
        "data/092de687-cd0d-4583-b872-bc2908dff3ba.jsonl",
        "data/86fb7a89-abfa-4e84-b862-5983e93c0b3b.jsonl",
        "data/ccs-viewer-tests.jsonl",
    ];

    fn deserialize_file(path: &str) -> usize {
        deserialize_file_collecting(path, None)
    }

    fn deserialize_file_collecting(path: &str, mut labels: Option<&mut HashSet<String>>) -> usize {
        let file = File::open(path).expect("sample JSONL file should exist");
        let reader = BufReader::new(file);
        let mut count = 0;
        for (i, line) in reader.lines().enumerate() {
            let line = line.unwrap();
            if line.trim().is_empty() {
                continue;
            }
            let result = serde_json::from_str::<Record>(&line);
            assert!(
                result.is_ok(),
                "line {} failed: {}",
                i + 1,
                result.unwrap_err()
            );
            if let (Ok(record), Some(labels)) = (&result, labels.as_deref_mut()) {
                labels.insert(record.label().to_string());
            }
            count += 1;
        }
        count
    }

    #[test]
    fn deserialize_sample_31ba() {
        assert_eq!(
            deserialize_file("data/31ba272b-f7c2-436b-a017-269e27a64d07.jsonl"),
            22
        );
    }

    #[test]
    fn deserialize_sample_997a() {
        assert_eq!(
            deserialize_file("data/997afb98-c6aa-4f4a-92ac-a841e040414b.jsonl"),
            461
        );
    }

    #[test]
    fn deserialize_sample_092d() {
        assert_eq!(
            deserialize_file("data/092de687-cd0d-4583-b872-bc2908dff3ba.jsonl"),
            224
        );
    }

    #[test]
    fn deserialize_sample_86fb() {
        assert_eq!(
            deserialize_file("data/86fb7a89-abfa-4e84-b862-5983e93c0b3b.jsonl"),
            301
        );
    }

    /// Look up a dotted path in a serde_json::Value.
    /// Supports segments like "message", "usage", or array filtering
    /// like "content[tool_use]" (find element in array where type == "tool_use").
    fn value_at_path<'a>(val: &'a Value, path: &str) -> Option<&'a Value> {
        let mut current = val;
        for segment in path.split('.') {
            if let Some(idx) = segment.find('[') {
                let key = &segment[..idx];
                let filter_type = &segment[idx + 1..segment.len() - 1];
                let arr = current.get(key)?.as_array()?;
                current = arr
                    .iter()
                    .find(|el| el.get("type").and_then(|t| t.as_str()) == Some(filter_type))?;
            } else {
                current = current.get(segment)?;
            }
        }
        if current.is_null() {
            None
        } else {
            Some(current)
        }
    }

    /// Verify every Option field in every struct has at least one non-null
    /// occurrence across test data. This catches Option fields that are defined
    /// in a struct but never actually exercised by any test file.
    ///
    /// WARNING: This test uses a static list of Option fields per record type
    /// (see each struct's `optional_fields()` method). It cannot catch Option
    /// fields that are missing from those lists — those fields will silently
    /// remain untested (always None). When adding a new Option field to a
    /// struct, you must also add its camelCase JSON name to the corresponding
    /// `optional_fields()` list.
    #[test]
    fn all_optional_fields_seen() {
        let field_map = Record::optional_fields_by_type();
        let mut seen: HashSet<(String, String)> = HashSet::new();

        for path in TEST_FILES {
            let file = File::open(path).expect("test file should exist");
            let reader = BufReader::new(file);
            for line in reader.lines() {
                let line = line.unwrap();
                if line.trim().is_empty() {
                    continue;
                }
                let val: Value = match serde_json::from_str(&line) {
                    Ok(v) => v,
                    Err(_) => continue,
                };
                let record_type = match val.get("type").and_then(|t| t.as_str()) {
                    Some(t) => t,
                    None => continue,
                };
                for &(rtype, fields) in &field_map {
                    if rtype != record_type {
                        continue;
                    }
                    for field in fields {
                        if value_at_path(&val, field).is_some() {
                            seen.insert((record_type.to_string(), field.to_string()));
                        }
                    }
                }
            }
        }

        let mut never_seen = Vec::new();
        for &(rtype, fields) in &field_map {
            for field in fields {
                if !seen.contains(&(rtype.to_string(), field.to_string())) {
                    never_seen.push(format!("{rtype}.{field}"));
                }
            }
        }
        never_seen.sort();
        assert!(
            never_seen.is_empty(),
            "Option fields never seen as Some in test data: {never_seen:?}"
        );
    }

    #[test]
    fn all_variants_covered() {
        let mut seen = HashSet::new();
        for path in TEST_FILES {
            deserialize_file_collecting(path, Some(&mut seen));
        }
        let expected: HashSet<String> =
            Record::all_labels().iter().map(|s| s.to_string()).collect();
        let missing: Vec<_> = expected.difference(&seen).collect();
        assert!(
            missing.is_empty(),
            "Record variants not covered by test data: {missing:?}"
        );
    }
}

use std::collections::{BTreeMap, HashMap};
use std::fs::File;
use std::io::{BufRead, BufReader};
use std::path::PathBuf;

use clap::Parser;

use ccs_viewer::types::Record;

#[derive(Parser)]
#[command(version, about = "Claude Code session JSONL viewer")]
struct Cli {
    /// File or directory glob patterns to process
    #[arg(required = true)]
    patterns: Vec<String>,

    /// Show per-file summary lines
    #[arg(short, long)]
    list: bool,

    /// Show grouped error details
    #[arg(short, long)]
    errors: bool,

    /// Recursively search directories for matching files
    #[arg(short, long)]
    recursive: bool,

    /// File glob pattern for recursive mode (repeatable, default: *.jsonl)
    #[arg(long = "glob")]
    globs: Vec<String>,
}

/// Resolve CLI patterns into a list of file paths.
fn resolve_files(cli: &Cli) -> Vec<PathBuf> {
    let mut files = Vec::new();

    if cli.recursive {
        let file_globs: Vec<&str> = if cli.globs.is_empty() {
            vec!["*.jsonl"]
        } else {
            cli.globs.iter().map(|s| s.as_str()).collect()
        };

        // Expand positional patterns as directory globs.
        for pattern in &cli.patterns {
            let dirs: Vec<PathBuf> = match glob::glob(pattern) {
                Ok(paths) => paths
                    .filter_map(|p| p.ok())
                    .filter(|p| p.is_dir())
                    .collect(),
                Err(e) => {
                    eprintln!("Bad pattern {pattern:?}: {e}");
                    std::process::exit(1);
                }
            };
            if dirs.is_empty() {
                eprintln!("No directories match {pattern:?}");
                std::process::exit(1);
            }
            for dir in &dirs {
                for fg in &file_globs {
                    let full = format!("{}/**/{fg}", dir.display());
                    match glob::glob(&full) {
                        Ok(paths) => {
                            for entry in paths.flatten() {
                                if entry.is_file() {
                                    files.push(entry);
                                }
                            }
                        }
                        Err(e) => {
                            eprintln!("Bad glob {full:?}: {e}");
                            std::process::exit(1);
                        }
                    }
                }
            }
        }
    } else {
        let file_globs: Vec<&str> = if cli.globs.is_empty() {
            vec!["*.jsonl"]
        } else {
            cli.globs.iter().map(|s| s.as_str()).collect()
        };

        for pattern in &cli.patterns {
            // Check if pattern is a literal directory path first.
            let path = PathBuf::from(pattern);
            if path.is_dir() {
                // Directory: expand file globs inside it (non-recursive).
                for fg in &file_globs {
                    let full = format!("{}/{fg}", path.display());
                    match glob::glob(&full) {
                        Ok(paths) => {
                            for entry in paths.flatten() {
                                if entry.is_file() {
                                    files.push(entry);
                                }
                            }
                        }
                        Err(e) => {
                            eprintln!("Bad glob {full:?}: {e}");
                            std::process::exit(1);
                        }
                    }
                }
            } else {
                // Treat as file glob pattern.
                match glob::glob(pattern) {
                    Ok(paths) => {
                        let mut matched = Vec::new();
                        for entry in paths.flatten() {
                            if entry.is_file() {
                                matched.push(entry);
                            } else if entry.is_dir() {
                                // Glob matched a directory: expand file
                                // globs inside it (non-recursive).
                                for fg in &file_globs {
                                    let full = format!("{}/{fg}", entry.display());
                                    if let Ok(inner) = glob::glob(&full) {
                                        for f in inner.flatten() {
                                            if f.is_file() {
                                                matched.push(f);
                                            }
                                        }
                                    }
                                }
                            }
                        }
                        if matched.is_empty() {
                            eprintln!("No files match {pattern:?}");
                            std::process::exit(1);
                        }
                        files.extend(matched);
                    }
                    Err(e) => {
                        eprintln!("Bad pattern {pattern:?}: {e}");
                        std::process::exit(1);
                    }
                }
            }
        }
    }

    files.sort();
    files.dedup();
    files
}

/// Key for grouping errors: the serde error message + record type.
#[derive(Hash, Eq, PartialEq)]
struct ErrorKey {
    message: String,
    record_type: String,
}

/// Tracks one group of identical errors across files.
struct ErrorGroup {
    count: usize,
    /// One representative file:line for grabbing test data.
    example_file: String,
    example_line: usize,
    /// How many distinct files contain this error.
    file_count: usize,
    /// Track which files we've seen (by index) to count distinct files.
    seen_files: Vec<usize>,
}

fn main() {
    let cli = Cli::parse();
    let files = resolve_files(&cli);

    if files.is_empty() {
        eprintln!("No files to process");
        std::process::exit(1);
    }

    let mut total_records: usize = 0;
    let mut total_errors: usize = 0;
    let mut error_groups: HashMap<ErrorKey, ErrorGroup> = HashMap::new();

    for (file_idx, path) in files.iter().enumerate() {
        let file = File::open(path).unwrap_or_else(|e| {
            eprintln!("Error opening {}: {e}", path.display());
            std::process::exit(1);
        });

        let reader = BufReader::new(file);
        let mut counts: BTreeMap<&str, usize> = BTreeMap::new();
        let mut file_errors: usize = 0;
        let filename = path
            .file_name()
            .map(|f| f.to_string_lossy().into_owned())
            .unwrap_or_else(|| path.display().to_string());

        for (i, line) in reader.lines().enumerate() {
            let line = line.unwrap_or_else(|e| {
                eprintln!("Error reading line {}: {e}", i + 1);
                std::process::exit(1);
            });
            if line.trim().is_empty() {
                continue;
            }
            match serde_json::from_str::<Record>(&line) {
                Ok(record) => {
                    *counts.entry(record.label()).or_insert(0) += 1;
                }
                Err(e) => {
                    file_errors += 1;
                    let record_type = serde_json::from_str::<serde_json::Value>(&line)
                        .ok()
                        .and_then(|v| v.get("type")?.as_str().map(String::from))
                        .unwrap_or_else(|| "unknown".to_string());

                    let key = ErrorKey {
                        message: format!("{e}"),
                        record_type,
                    };
                    let group = error_groups.entry(key).or_insert_with(|| ErrorGroup {
                        count: 0,
