            eprintln!("Error opening {}: {e}", path.display());
            std::process::exit(1);
        });

        let filename = path
            .file_name()
            .map(|f| f.to_string_lossy().into_owned())
            .unwrap_or_else(|| path.display().to_string());

        // Handle .meta.json files as single-object JSON (not JSONL).
        if filename.ends_with(".meta.json") {
            let result: Result<AgentMeta, _> = serde_json::from_reader(file);
            match result {
                Ok(_meta) => {
                    total_records += 1;
                    if cli.list {
                        println!("{filename}: agent-meta (ok)");
                    }
                }
                Err(e) => {
                    total_errors += 1;
                    let key = ErrorKey {
                        message: format!("{e}"),
                        record_type: "agent-meta".to_string(),
                    };
                    let group = error_groups.entry(key).or_insert_with(|| ErrorGroup {
                        count: 0,
                        example_file: filename.clone(),
                        example_line: 1,
                        file_count: 0,
                        seen_files: Vec::new(),
                    });
                    group.count += 1;
                    if !group.seen_files.contains(&file_idx) {
                        group.seen_files.push(file_idx);
                        group.file_count += 1;
                    }
                    if cli.list {
                        println!("{filename}: agent-meta (error)");
                    }
                }
            }
            continue;
        }

        let reader = BufReader::new(file);
        let mut counts: BTreeMap<&str, usize> = BTreeMap::new();
        let mut file_errors: usize = 0;

        for (i, line) in reader.lines().enumerate() {
            let line = line.unwrap_or_else(|e| {
                eprintln!("Error reading line {}: {e}", i + 1);
                std::process::exit(1);
            });
            if line.trim().is_empty() {
                continue;
            }
            match serde_json::from_str::<Record>(&line) {
                Ok(record) => {
                    *counts.entry(record.label()).or_insert(0) += 1;
                }
                Err(e) => {
                    file_errors += 1;
                    let record_type = serde_json::from_str::<serde_json::Value>(&line)
                        .ok()
                        .and_then(|v| v.get("type")?.as_str().map(String::from))
                        .unwrap_or_else(|| "unknown".to_string());

                    let key = ErrorKey {
                        message: format!("{e}"),
                        record_type,
                    };
                    let group = error_groups.entry(key).or_insert_with(|| ErrorGroup {
                        count: 0,
                        example_file: filename.clone(),
                        example_line: i + 1,
                        file_count: 0,
                        seen_files: Vec::new(),
                    });
                    group.count += 1;
                    if !group.seen_files.contains(&file_idx) {
                        group.seen_files.push(file_idx);
                        group.file_count += 1;
                    }
                }
            }
        }

        let file_total: usize = counts.values().sum();
        total_records += file_total;
        total_errors += file_errors;

        if cli.list {
            let mut parts = vec![
                format!("errors: {file_errors}"),
                format!("records: {file_total}"),
            ];
            for (label, count) in &counts {
                parts.push(format!("{label}: {count}"));
            }
            println!("{filename}: {}", parts.join(", "));
        }
    }

    let file_count = files.len();
    println!(
        "{}Summary: {file_count} file(s), {total_records} records, {total_errors} errors",
        if cli.list { "\n" } else { "" }
    );

    if cli.errors && !error_groups.is_empty() {
        println!("\nErrors:");
        let mut groups: Vec<_> = error_groups.into_iter().collect();
        groups.sort_by(|a, b| b.1.count.cmp(&a.1.count));
        for (key, group) in &groups {
            println!(
                "  {}x {} in {} ({}:{} in {} file(s))",
                group.count,
                key.message,
                key.record_type,
                group.example_file,
                group.example_line,
                group.file_count,
            );
        }
    }

    if total_errors > 0 {
        std::process::exit(1);
    }
}

